<?php
/* TimeWalk Japan module: Free Views of Tokyo */
if (!defined('ABSPATH')) exit;
final class TWJ_Free_Views_Module {
 const VERSION='1.1.0';
 const CATEGORY_SLUG='free-views-tokyo';
 function __construct(){add_action('wp_loaded',array($this,'provision'),40);add_filter('the_content',array($this,'append_links'),30);add_action('wp_enqueue_scripts',array($this,'assets'));add_action('wp_footer',array($this,'footer_link'),30);add_filter('document_title_parts',array($this,'title'),20);add_action('wp_head',array($this,'meta'),2);}
 private function url($slug){$p=get_page_by_path($slug,OBJECT,'page');return $p?get_permalink($p):home_url('/'.$slug.'/');}
 private function category_id(){ $t=term_exists('Free Views of Tokyo','category'); if(!$t)$t=wp_insert_term('Free Views of Tokyo','category',array('slug'=>self::CATEGORY_SLUG)); if(is_wp_error($t))return 0; return is_array($t)?(int)$t['term_id']:(int)$t; }
 private function article_content($type){$hub=esc_url($this->url('free-views-tokyo'));if($type==='metro')return '<!-- wp:paragraph --><p>Tokyo Metropolitan Government Building offers one of the most accessible free views in central Tokyo. The observatories are also a useful place to understand the scale of Shinjuku’s transformation into a high-rise business district.</p><!-- /wp:paragraph --><!-- wp:heading --><h2>Why This View Matters</h2><!-- /wp:heading --><!-- wp:paragraph --><p>From the upper floors, visitors can compare Shinjuku’s dense tower district with lower residential areas farther west. On clear days, distant mountains may also be visible. The view helps explain how Tokyo expanded beyond its older eastern core.</p><!-- /wp:paragraph --><!-- wp:heading --><h2>The Building and Shinjuku’s Urban History</h2><!-- /wp:heading --><!-- wp:paragraph --><p>The Tokyo Metropolitan Government moved to Shinjuku in 1991. The monumental complex, designed by Kenzo Tange, became a symbol of the city’s late twentieth-century administrative and commercial growth.</p><!-- /wp:paragraph --><!-- wp:heading --><h2>Before You Visit</h2><!-- /wp:heading --><!-- wp:list --><ul><li>Admission is free</li><li>Opening hours and closures may change</li><li>Security checks may apply</li><li>Check the official website before visiting</li><li>Photography rules may vary</li></ul><!-- /wp:list --><!-- wp:heading --><h2>Explore More Free Views</h2><!-- /wp:heading --><!-- wp:paragraph --><p><a href="'.$hub.'">Explore more free views of Tokyo</a></p><!-- /wp:paragraph -->';return '<!-- wp:paragraph --><p>KITTE Garden is a free rooftop space overlooking Tokyo Station. It combines one of the city’s most recognizable railway views with the history of Japan’s former central post office.</p><!-- /wp:paragraph --><!-- wp:heading --><h2>Why This View Matters</h2><!-- /wp:heading --><!-- wp:paragraph --><p>The rooftop offers a clear view of Tokyo Station’s Marunouchi side and the railway tracks entering the terminal. It is a useful place to see how rail transport, office development and preserved architecture meet in central Tokyo.</p><!-- /wp:paragraph --><!-- wp:heading --><h2>Postal History and Modern Marunouchi</h2><!-- /wp:heading --><!-- wp:paragraph --><p>KITTE forms part of JP Tower, which incorporates preserved elements of the former Tokyo Central Post Office. The site shows how older public buildings have been integrated into large modern redevelopment projects.</p><!-- /wp:paragraph --><!-- wp:heading --><h2>Before You Visit</h2><!-- /wp:heading --><!-- wp:list --><ul><li>Admission to the rooftop garden is free</li><li>Opening hours may change</li><li>The garden may close because of weather or maintenance</li><li>Tripod and commercial photography rules may apply</li><li>Check the official website before visiting</li></ul><!-- /wp:list --><!-- wp:heading --><h2>Explore More Free Views</h2><!-- /wp:heading --><!-- wp:paragraph --><p><a href="'.$hub.'">Explore more free views of Tokyo</a></p><!-- /wp:paragraph -->';}
 private function upsert_post($slug,$title,$excerpt,$content,$cat_id,$meta){$old=get_page_by_path($slug,OBJECT,'post');$a=array('post_type'=>'post','post_status'=>'publish','post_title'=>$title,'post_name'=>$slug,'post_excerpt'=>$excerpt,'post_content'=>$content,'post_category'=>array($cat_id),'comment_status'=>'closed','ping_status'=>'closed');if($old)$a['ID']=$old->ID;$id=$old?wp_update_post(wp_slash($a),true):wp_insert_post(wp_slash($a),true);if(is_wp_error($id)||!$id)return 0;foreach($meta as $k=>$v)update_post_meta($id,$k,$v);return (int)$id;}
 private function query_block($cat_id){return '<!-- wp:query {"queryId":41,"query":{"perPage":12,"pages":0,"offset":0,"postType":"post","order":"desc","orderBy":"date","author":"","search":"","exclude":[],"sticky":"","inherit":false,"taxQuery":{"category":['.$cat_id.']}},"displayLayout":{"type":"flex","columns":3}} --><div class="wp-block-query"><!-- wp:post-template --><!-- wp:group {"className":"twj-view-query-card","layout":{"type":"constrained"}} --><div class="wp-block-group twj-view-query-card"><!-- wp:post-featured-image {"isLink":true,"aspectRatio":"16/9"} /--><!-- wp:post-title {"isLink":true,"fontSize":"medium"} /--><!-- wp:post-excerpt {"moreText":"Read the Guide"} /--><!-- wp:post-date {"fontSize":"small"} /--></div><!-- /wp:group --><!-- /wp:post-template --><!-- wp:query-no-results --><!-- wp:paragraph --><p>No guides are available yet. New free viewpoints will be added soon.</p><!-- /wp:paragraph --><!-- /wp:query-no-results --><!-- wp:query-pagination {"layout":{"type":"flex","justifyContent":"space-between"}} --><!-- wp:query-pagination-previous /--><!-- wp:query-pagination-numbers /--><!-- wp:query-pagination-next /--><!-- /wp:query-pagination --></div><!-- /wp:query -->';}
 private function hub_content($cat_id){return '<!-- wp:heading {"level":1} --><h1>Free Views of Tokyo</h1><!-- /wp:heading --><!-- wp:paragraph --><p>Tokyo’s skyline is not limited to expensive towers. City halls, public observation rooms, rooftop gardens and commercial terraces offer remarkable views for free. These places also reveal how Tokyo grew—from Edo-period coastlines and railway corridors to modern redevelopment districts.</p><!-- /wp:paragraph --><!-- wp:buttons --><div class="wp-block-buttons"><!-- wp:button --><div class="wp-block-button"><a class="wp-block-button__link wp-element-button" href="#viewpoints">Browse the Viewpoints</a></div><!-- /wp:button --><!-- wp:button {"className":"is-style-outline"} --><div class="wp-block-button is-style-outline"><a class="wp-block-button__link wp-element-button" href="'.esc_url($this->url('tokyo')).'">Explore Tokyo</a></div><!-- /wp:button --></div><!-- /wp:buttons --><!-- wp:heading --><h2>More Than a Skyline</h2><!-- /wp:heading --><!-- wp:paragraph --><p>This guide focuses on viewpoints that can be entered without an observation-deck ticket. It includes government buildings, public facilities, rooftop gardens and shared commercial terraces. The aim is not only to find a beautiful view, but to read Tokyo’s history, geography, transport, architecture and redevelopment from above. Hours, closures and access conditions can change, so always confirm current official information before visiting.</p><!-- /wp:paragraph --><!-- wp:heading {"anchor":"viewpoints"} --><h2 id="viewpoints">Free Viewpoints in Tokyo</h2><!-- /wp:heading -->'.$this->query_block($cat_id).'<!-- wp:heading --><h2>Before You Visit</h2><!-- /wp:heading --><!-- wp:list --><ul><li>Opening hours, closure days and entry procedures may change.</li><li>Respect shops, restaurant guests and other visitors in shared commercial spaces.</li><li>Tripods, long photo sessions and commercial photography may be restricted.</li><li>Weather, glass, direction and seasonal light can change what is visible.</li><li>Check each facility’s official website before travelling.</li></ul><!-- /wp:list --><!-- wp:heading --><h2>Read Tokyo from Above</h2><!-- /wp:heading --><!-- wp:paragraph --><p>From above, Tokyo becomes easier to read. Railway lines reveal how neighborhoods developed. Rivers and lowlands explain the city’s geography. Former industrial sites show the scale of redevelopment. Preserved buildings reveal how older Tokyo survives inside the modern city.</p><!-- /wp:paragraph --><!-- wp:heading --><h2>Keep Exploring Tokyo</h2><!-- /wp:heading --><!-- wp:paragraph --><p><a href="'.esc_url($this->url('tokyo')).'">Explore Tokyo</a> · <a href="'.esc_url($this->url('self-guided-walks')).'">Self-Guided Walks</a> · <a href="'.esc_url($this->url('stories')).'">Stories</a> · <a href="'.esc_url($this->url('events')).'">Events</a></p><!-- /wp:paragraph -->';}
 function provision(){if((string)get_option('twj_free_views_version','')===self::VERSION)return;$cat=$this->category_id();if(!$cat)return;$p1=$this->upsert_post('tokyo-metropolitan-government-observatory-guide','Tokyo Metropolitan Government Observatories: Free Views over Shinjuku','Visit one of Tokyo’s best-known free observation decks and see how Shinjuku grew into a major business district. This short guide covers the view, the building and practical visiting information.',$this->article_content('metro'),$cat,array('_twj_free_view'=>'1','_yoast_wpseo_metadesc'=>'Visit Tokyo Metropolitan Government Observatories for free views over Shinjuku and learn how the district became Tokyo’s major high-rise centre.','rank_math_description'=>'Visit Tokyo Metropolitan Government Observatories for free views over Shinjuku and learn how the district became Tokyo’s major high-rise centre.'));$p2=$this->upsert_post('kitte-garden-tokyo-station-guide','KITTE Garden: Free Views of Tokyo Station and Marunouchi','See Tokyo Station from a free rooftop garden above KITTE Marunouchi. This short guide introduces the view, the former central post office and the changing Marunouchi district.',$this->article_content('kitte'),$cat,array('_twj_free_view'=>'1','_yoast_wpseo_metadesc'=>'Visit KITTE Garden for free views of Tokyo Station and learn how postal history and modern Marunouchi redevelopment meet in one place.','rank_math_description'=>'Visit KITTE Garden for free views of Tokyo Station and learn how postal history and modern Marunouchi redevelopment meet in one place.'));$page=get_page_by_path('free-views-tokyo',OBJECT,'page');$a=array('post_type'=>'page','post_status'=>'publish','post_title'=>'Free Views of Tokyo','post_name'=>'free-views-tokyo','post_content'=>$this->hub_content($cat),'comment_status'=>'closed','ping_status'=>'closed');if($page)$a['ID']=$page->ID;$id=$page?wp_update_post(wp_slash($a),true):wp_insert_post(wp_slash($a),true);if(!is_wp_error($id)&&$id&&$p1&&$p2){update_post_meta($id,'_twj_free_views','1');update_post_meta($id,'_twj_seo_title','Free Views of Tokyo | Observation Decks, Rooftops and Historic Cityscapes');update_post_meta($id,'_twj_meta_description','Discover free observation decks, rooftop gardens and hidden viewpoints across Tokyo. Learn what you can see, how to visit, and the history behind each cityscape.');update_option('twj_free_views_version',self::VERSION,false);}}
 function append_links($content){if(!in_the_loop()||!is_main_query())return$content;if(is_page('free-views-tokyo'))return$content;$box='<section class="twj-free-link-card"><h2>Free Views of Tokyo</h2><p>Discover free observation decks, rooftop gardens and lesser-known viewpoints—and learn the history behind the view.</p><a class="twj-btn" href="'.esc_url($this->url('free-views-tokyo')).'">Explore Free Views</a></section>';if(is_front_page()||is_page(15)||is_page('tokyo'))return$content.$box;return$content;}
 function footer_link(){?><script>document.addEventListener('DOMContentLoaded',function(){if(document.querySelector('footer a[href*="free-views-tokyo"]'))return;var g=document.querySelector('footer nav,footer .wp-block-navigation,footer .footer-widget-area');if(g){var a=document.createElement('a');a.href='<?php echo esc_js($this->url('free-views-tokyo'));?>';a.textContent='Free Views of Tokyo';g.appendChild(a);}});</script><?php }
 function title($parts){if(is_page('free-views-tokyo'))$parts['title']='Free Views of Tokyo | Observation Decks, Rooftops and Historic Cityscapes';return$parts;}
 function meta(){if(is_page('free-views-tokyo'))echo '<meta name="description" content="Discover free observation decks, rooftop gardens and hidden viewpoints across Tokyo. Learn what you can see, how to visit, and the history behind each cityscape.">';}
 function assets(){wp_register_style('twj-free-views',false,array(),self::VERSION);wp_enqueue_style('twj-free-views');wp_add_inline_style('twj-free-views','.twj-view-query-card{height:100%;padding:16px;border:1px solid #e2e7ed;border-radius:12px;background:#fff;box-shadow:0 6px 18px rgba(23,32,51,.06)}.twj-view-query-card .wp-block-post-featured-image{margin:0 0 12px}.twj-view-query-card .wp-block-post-featured-image img{border-radius:8px}.twj-free-link-card{margin:54px 0!important;padding:24px;border:1px solid #e2e7ed;border-radius:12px;background:#f7f9fb}.twj-btn{display:inline-block;padding:10px 16px;border-radius:999px;background:#172033;color:#fff!important;text-decoration:none!important;font-weight:700}@media(max-width:781px){.wp-block-post-template.is-flex-container{grid-template-columns:repeat(2,minmax(0,1fr))!important}}@media(max-width:600px){.wp-block-post-template.is-flex-container{grid-template-columns:1fr!important}}');}
}
new TWJ_Free_Views_Module();